 53→private fun ASTNode.nextLeafStrict(): ASTNode? {
 54→    val nextSibling: ASTNode? = treeNext
 55→    if (nextSibling != null) {
 56→        return nextSibling.firstChildLeafOrSelf()
 57→    }
 58→    return treeParent?.nextLeafStrict()
 59→}
