256→public fun ASTNode.upsertWhitespaceBeforeMe(text: String) {
257→    if (this is LeafElement) {
258→        if (this.elementType == WHITE_SPACE) {
259→            return replaceWhitespaceWith(text)
260→        }
261→        val previous = treePrev ?: prevLeaf()
262→        if (previous != null && previous.elementType == WHITE_SPACE) {
263→            previous.replaceWhitespaceWith(text)
264→        } else {
265→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
266→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
267→            }
268→        }
269→    } else {
270→        val prevLeaf =
271→            requireNotNull(prevLeaf()) {
272→                "Can not upsert a whitespace if the first node is a non-leaf node"
273→            }
274→        prevLeaf.upsertWhitespaceAfterMe(text)
275→    }
276→}
