278→private fun ASTNode.replaceWhitespaceWith(text: String) {
279→    require(this.elementType == WHITE_SPACE)
280→    if (this.text != text) {
281→        (this.psi as LeafElement).rawReplaceWithText(text)
282→    }
283→}
