433→/**
434→ * Get all leaves on the same line as the given node including the whitespace indentation. Note that the whitespace indentation may start
435→ * with zero or more newline characters.
436→ */
437→public fun ASTNode.leavesOnLine(): Sequence<ASTNode> {
438→    val lastLeafOnLineOrNull = getLastLeafOnLineOrNull()
439→    return getFirstLeafOnLineOrSelf()
440→        .leavesIncludingSelf()
441→        .takeWhile { lastLeafOnLineOrNull == null || it.prevLeaf() != lastLeafOnLineOrNull }
