448→/**
449→ * Get the total length of all leaves on the same line as the given node including the whitespace indentation but excluding all leading
450→ * newline characters in the whitespace indentation.
451→ */
452→public fun ASTNode.lineLengthWithoutNewlinePrefix(): Int =
453→    leavesOnLine()
454→        .joinToString(separator = "") { it.text }
455→        // If a line is preceded by a blank line then the ident contains multiple newline chars
456→        .dropWhile { it == '\n' }
457→        // In case the last element on the line would contain a newline then only include chars before that newline. Note that this should
458→        // not occur if the AST is parsed correctly
459→        .takeWhile { it != '\n' }
460→        .length
