import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.EOL_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.WHITE_SPACE
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.isWhiteSpaceWithNewline
import com.pinterest.ktlint.rule.engine.core.api.leavesOnLine
import com.pinterest.ktlint.rule.engine.core.api.nextCodeLeaf
import com.pinterest.ktlint.rule.engine.core.api.nextLeaf
import com.pinterest.ktlint.rule.engine.core.api.prevCodeLeaf
import com.pinterest.ktlint.rule.engine.core.api.prevLeaf
import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.PsiComment
import org.jetbrains.kotlin.com.intellij.psi.PsiElement
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafPsiElement
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.PsiWhiteSpaceImpl
import org.jetbrains.kotlin.psi.KtAnnotated
import org.jetbrains.kotlin.psi.KtPsiFactory
import org.jetbrains.kotlin.psi.psiUtil.endOffset
import org.jetbrains.kotlin.psi.psiUtil.startOffset

/**
 * Migrates deprecated "ktlint-disable" / "ktlint-enable" directives to @Suppress annotations.
 *
 * Note that the old comment directives are no longer interpreted as ktlint suppressions.
 */
public class KtlintDisableDirectiveRule :
    StandardRule(
        id = "a-ktlint-disable-directive",
    ) {
    private val openBlockDirectives = mutableListOf<BlockDirective>()

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.psi !is PsiComment) {
            return
        }

        when (val directive = node.parseDirectiveOrNull()) {
            is Directive.EolDisable -> {
                emit(node.startOffset, "Deprecated ktlint-disable directive. Replace with @Suppress annotation", true)
                if (autoCorrect) {
                    val target =
                        node
                            .prevCodeLeaf()
                            ?.psi
                            ?.let { findFirstAnnotatableParent(it) }
                    if (target != null) {
                        insertSuppressAnnotationBefore(target, directive.suppressionArgs)
                        removeEolCommentDirective(node)
                    }
                }
            }

            is Directive.BlockDisableStart -> {
                openBlockDirectives.add(BlockDirective(node, directive.suppressionArgs))
            }

            is Directive.BlockDisableEnd -> {
                val open =
                    openBlockDirectives
                        .lastOrNull { it.suppressionArgs == directive.suppressionArgs }
                if (open != null) {
                    openBlockDirectives.remove(open)

                    val firstCodeLeaf = open.node.nextCodeLeaf(skipSubtree = true)
                    val lastCodeLeaf = node.prevCodeLeaf()

                    val target =
                        if (firstCodeLeaf != null && lastCodeLeaf != null) {
                            findAnnotatableElementSpanningRange(
                                start = firstCodeLeaf.psi,
                                end = lastCodeLeaf.psi,
                                startOffset = open.node.startOffset,
                                endOffset = node.startOffset,
                            )
                        } else {
                            null
                        }

                    if (target == null) {
                        emit(
                            open.node.startOffset,
                            "Deprecated ktlint-disable block directive. Replace with @Suppress annotation (manual migration needed for blocks spanning multiple statements)",
                            false,
                        )
                    } else {
                        emit(open.node.startOffset, "Deprecated ktlint-disable/enable block directive. Replace with @Suppress annotation", true)
                        if (autoCorrect) {
                            insertSuppressAnnotationBefore(target, directive.suppressionArgs)
                            removeBlockCommentDirective(open.node)
                            removeBlockCommentDirective(node)
                        }
                    }
                }
            }

            null -> Unit
        }
    }

    override fun afterLastNode() {
        // Convert any remaining unmatched block disable directives to a file level suppression when possible.
        // This happens frequently for disabling import ordering in a file.
        openBlockDirectives
            .filter { it.node.prevCodeLeaf() == null }
            .forEach { open ->
                val root = open.node.treeParent ?: return@forEach
                val firstLeaf = root.firstChildNode?.firstChildNode ?: return@forEach
                val project = firstLeaf.psi.project
                val psiFactory = KtPsiFactory(project, markGenerated = false)
                val fileSuppress = psiFactory.createAnnotationEntry(createSuppressAnnotationText(isFileAnnotation = true, suppressionArgs = open.suppressionArgs))
                val anchorLeaf = root.firstChildNode.firstChildNode.firstChildNode ?: root.firstChildNode
                (anchorLeaf.psi as? LeafPsiElement)?.rawInsertBeforeMe(fileSuppress)
                (anchorLeaf.psi as? LeafPsiElement)?.rawInsertBeforeMe(PsiWhiteSpaceImpl("\n"))
                removeBlockCommentDirective(open.node)
            }
        openBlockDirectives.clear()
    }

    private data class BlockDirective(
        val node: ASTNode,
        val suppressionArgs: List<String>,
    )

    private sealed class Directive {
        data class EolDisable(val suppressionArgs: List<String>) : Directive()

