    private fun insertSuppressAnnotationBefore(
        target: KtAnnotated,
        suppressionArgs: List<String>,
    ) {
        val project = target.project
        val psiFactory = KtPsiFactory(project, markGenerated = false)
        val annotationEntry =
            psiFactory.createAnnotationEntry(
                createSuppressAnnotationText(
                    isFileAnnotation = false,
                    suppressionArgs = suppressionArgs,
                ),
            )

        val firstLeaf = target.node.firstChildLeafOrSelf()

        val precedingWhitespaceWithNewline = firstLeaf.prevLeaf { it.isWhiteSpaceWithNewline() }
        if (precedingWhitespaceWithNewline != null && precedingWhitespaceWithNewline.elementType == WHITE_SPACE) {
            val wsText = precedingWhitespaceWithNewline.text
            val lastNewlineIndex = wsText.lastIndexOf('\n')
            val prefix = wsText.substring(0, lastNewlineIndex + 1)
            val indent = wsText.substring(lastNewlineIndex + 1)
            (precedingWhitespaceWithNewline.psi as LeafPsiElement).rawReplaceWithText(
                prefix + indent + annotationEntry.text + "\n" + indent,
            )
        } else {
            val leafPsi = firstLeaf.psi as LeafPsiElement
            leafPsi.rawInsertBeforeMe(annotationEntry)
            leafPsi.rawInsertBeforeMe(PsiWhiteSpaceImpl("\n"))
        }
    }

    private fun insertFileSuppressAnnotationAtTop(
        root: ASTNode,
        suppressionArgs: List<String>,
    ) {
        val firstLeaf = root.firstChildLeafOrSelf()
        val leafPsi = firstLeaf.psi as LeafPsiElement
        val psiFactory = KtPsiFactory(leafPsi.project, markGenerated = false)
        val fileAnnotation =
            psiFactory.createAnnotationEntry(
                createSuppressAnnotationText(
                    isFileAnnotation = true,
                    suppressionArgs = suppressionArgs,
                ),
            )
        leafPsi.rawInsertBeforeMe(fileAnnotation)
        if (!(firstLeaf.elementType == WHITE_SPACE && firstLeaf.textContains('\n'))) {
            leafPsi.rawInsertBeforeMe(PsiWhiteSpaceImpl("\n"))
        }
    }

    private fun createSuppressAnnotationText(
        isFileAnnotation: Boolean,
        suppressionArgs: List<String>,
    ): String {
        val prefix = if (isFileAnnotation) "@file:" else "@"
        val args = suppressionArgs.joinToString(separator = ", ") { "\"$it\"" }
        return "${prefix}Suppress($args)"
    }

    private fun removeEolCommentDirective(node: ASTNode) {
        // Remove whitespace between code and the directive comment
        node
            .prevLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE && !it.textContains('\n') }
            ?.let { (it.psi as LeafPsiElement).rawRemove() }
        (node.psi as LeafPsiElement).rawRemove()
    }

    private fun removeBlockCommentDirective(node: ASTNode) {
        val leavesOnLine = node.leavesOnLine().toList()

        // In case the directive is the only thing on the line, try to keep the line clean by removing trailing whitespace.
        node
            .nextLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE && !it.textContains('\n') }
            ?.let { (it.psi as LeafPsiElement).rawRemove() }
        (node.psi as LeafPsiElement).rawRemove()

        // If the line only contained the comment, remove redundant whitespace on that line (indentation stays).
        if (leavesOnLine.all { it == node || it.elementType == WHITE_SPACE }) {
            leavesOnLine
                .filter { it.elementType == WHITE_SPACE && !it.textContains('\n') }
                .forEach { (it.psi as LeafPsiElement).rawRemove() }
        }
    }

    private companion object {
        private const val KTLINT_DISABLE = "ktlint-disable"
        private const val KTLINT_ENABLE = "ktlint-enable"
    }
